		function getLines(text) {
			text = text.trim();
			if (text.length <= 16) return [text];
			var lines = [];
			while (text.length > 16) {
				var idx = text.lastIndexOf(" ", 16);
				if (idx === -1) {
					idx = 16;
				}
				lines.push(text.substring(0, idx));
				text = text.substring(idx).trim();
			}
			lines.push(text);
			if (!lines) return [];
			if (lines.length > 2) {
				lines = lines.slice(0, 2);
				lines[1] = lines[1] + "...";
			}
			return lines.map((l) => l.trim());
		}

		function measureText(text, fontSize) {
			if (text.length === 0) return { width: 0, height: 0 };
			var SPAN = document.createElement("span");
			SPAN.style.cssText =
				"display:inine-block;line-height:1;font-family:Arial;font-size:" +
				fontSize +
				"px";
			SPAN.innerHTML = text;
			var span = $(SPAN);
			$("body").append(span);
			var w = $(span).width();
			var h = $(span).height();
			span.remove();
			return { width: Math.ceil(w), height: Math.ceil(h) };
		}

		function getFontSize(txt, fs = 20) {
			var SPAN = document.createElement("span");
			SPAN.style.cssText =
				"display:inine-block;line-height:1;font-family:Arial;font-size:" +
				fs +
				"px";
			SPAN.innerHTML = txt;
			var span = $(SPAN);
			$("body").append(span);
			var w = $(span).width();
			var h = $(span).height();
			while ((w > 134 || h > 36) && fs > 16) {
				fs--;
				$(span).css("font-size", fs);
				w = $(span).width();
				h = $(span).height();
			}
			span.remove();
			return fs;
		}

		function handleLabelChange(newLabel, fullLabel) {
			if (selectedLabel) {
				selectedLabel.userData.fullLabel = fullLabel;
				if (newLabel.length === 0) {
					selectedLabel.setText("");
					return;
				}
				var lines = getLines(newLabel);
				selectedLabel.setText(lines.join("\n"));
				var fs = getFontSize(lines.join("<br>"));
				selectedLabel.setFontSize(fs);
			}
		}

